g>\\n      <bpmn:incoming>Flow_Staff_End</bpmn:incoming>\\n    </bpmn:endEvent>\\n    <bpmn:sequenceFlow id=\\"Flow_Start_Leader\\" sourceRef=\\"StartEvent_1\\" targetRef=\\"Task_Leader\\" />\\n    <bpmn:sequenceFlow id=\\"Flow_Leader_Gateway\\" sourceRef=\\"Task_Leader\\" targetRef=\\"Gateway_1\\" />\\n    <bpmn:sequenceFlow id=\\"Flow_Gateway_Manager\\" sourceRef=\\"Gateway_1\\" targetRef=\\"Task_Finance_Manager\\">\\n <bpmn:conditionExpression xsi:type=\\"bpmn:tFormalExpression\\">${amount &gt; 5000}</bpmn:conditionExpression>\\n    </bpmn:sequenceFlow>\\n    <bpmn:sequenceFlow id=\\"Flow_Gateway_Staff\\" sourceRef=\\"Gateway_1\\" targetRef=\\"Task_Finance_Staff\\">\\n      <bpmn:conditionExpression xsi:type=\\"bpmn:tFormalExpression\\">${amount &lt;= 5000}</bpmn:conditionExpression>\\n    </bpmn:sequenceFlow>\\n    <bpmn:sequenceFlow id=\\"Flow_Manager_End\\" sourceRef',
