  "summary": "将请假流程修改为报销审批流程，保留直属上级审批节点，将天数判断网关改为金额判断，金额>5000 走财务经理审批，否则走财务专员审批",
  "bpmnXml": "<?xml version=\\"1.0\\" encoding=\\"UTF-8\\"?>\\n<bpmn:definitions xmlns:bpmn=\\"http://www.omg.org/spec/BPMN/20100524/MODEL\\" xmlns:bpmndi=\\"http://www.omg.org/spec/BPMN/20100524/DI\\" xmlns:dc=\\"http://www.omg.org/spec/DD/20100524/DC\\" xmlns:di=\\"http://www.omg.org/spec/DD/20100524/DI\\" xmlns:xsi=\\"http://www.w3.org/2001/XMLSchema-instance\\" xmlns:flowable=\\"http://flowable.org/bpmn\\" targetNamespace=\\"http://flowable.org/processdef\\">\\n  <bpmn:process id=\\"leavetest\\" name=\\"报销审批\\" isExecutable=\\"true\\">\\n    <bpmn:startEvent id=\\"StartEvent_1\\" name=\\"开始\\" flowable:initiator=\\"initiator\\">\\n      <bpmn:outgoing>Flow_Start_Leader</bpmn:outgoing>\\n    </bpmn:startEvent>\\n    <bpmn:userTask id=\\"Task_Leader\\" name=\\"直属上级审批\\" flowable:assignee=\\"${flowSpelService.getInitiatorLeader(execution)}\\">\\n      <bpmn:incoming>Flow_Start_Leader</bpmn:incoming>\\n      <bpmn:outgoing>Flow_Leader_Gateway</bpmn:outgoing>\\n    </bpmn:userTask>\\n    <bpmn:exclusiveGateway id=\\"Gateway_1\\" name=\\"金额判断\\">\\n      <bpmn:incoming>Flow_Leader_Gateway</bpmn:incoming>\\n      <bpmn:outgoing>Flow_Gateway_Manager</bpmn:outgoing>\\n      <bpmn:outgoing>Flow_Gateway_Staff</bpmn:outgoing>\\n    </bpmn:exclusiveGateway>\\n    <bpmn:userTask id=\\"Task_Finance_Manager\\" name=\\"财务经理审批\\" flowable:candidateGroups=\\"finance_manager\\">\\n      <bpmn:incoming>Flow_Gateway_Manager</bpmn:incoming>\\n      <bpmn:outgoing>Flow_Manager_End</bpmn:outgoing>\\n    </bpmn:userTask>\\n    <bpmn:userTask id=\\"Task_Finance_Staff\\" name=\\"财务专员审批\\" flowable:candidateGroups=\\"finance_staff\\">\\n      <bpmn:incoming>Flow_Gateway_Staff</bpmn:incoming>\\n      <bpmn:outgoing>Flow_Staff_End</bpmn:outgoing>\\n    </bpmn:userTask>\\n    <bpmn:endEvent id=\\"EndEvent_1\\" name=\\"结束\\">\\n      <bpmn:incoming>Flow_Manager_End</bpmn:incoming>\\n      <bpmn:incoming>Flow_Staff_End</bpmn:incoming>\\n    </bpmn:endEvent>\\n    <bpmn:sequenceFlow id=\\"Flow_Start_Leader\\" sourceRef=\\"StartEvent_1\\" targetRef=\\"Task_Leader\\" />\\n    <bpmn:sequenceFlow id=\\"Flow_Leader_Gateway\\" sourceRef=\\"Task_Leader\\" targetRef=\\"Gateway_1\\" />\\n    <bpmn:sequenceFlow id=\\"Flow_Gateway_Manager\\" sourceRef=\\"Gateway_1\\" targetRef=\\"Task_Finance_Manager\\">\\n      <bpmn:conditionExpression xsi:type=\\"bpmn:tFormalExpression\\">${amount &gt; 5000}</bpmn:conditionExpression>\\n    </bpmn:sequenceFlow>\\n    <bpmn:sequenceFlow id=\\"Flow_Gateway_Staff\\" sourceRef=\\"Gateway_1\\" targetRef=\\"Task_Finance_Staff\\">\\n      <bpmn:conditionExpression xsi:type=\\"bpmn:tFormalExpression\\">${amount &lt;= 5000}</bpmn:conditionExpression>\\n    </bpmn:sequenceFlow>\\n    <bpmn:sequenceFlow id=\\"Flow_Manager_End\\" sourceRef=\\"Task_Finance_Manager\\" targetRef=\\"EndEvent_1\\" />\\n    <bpmn:sequenceFlow id=\\"Flow_Staff_End\\" sourceRef=\\"Task_Finance_Staff\\" targetRef=\\"EndEvent_1\\" />\\n  </bpmn:process>\\n  <bpmndi:BPMNDiagram id=\\"BPMNDiagram_1\\">\\n    <bpmndi:BPMNPlane id=\\"BPMNPlane_1\\" bpmnElement=\\"leavetest\\">\\n      <bpmndi:BPMNShape id=\\"StartEvent_1_di\\" bpmnElement=\\"StartEvent_1\\">\\n        <dc:Bounds x=\\"100\\" y=\\"150\\" width=\\"36\\" height=\\"36\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:B',
