 id=\\"Task_Apply_di\\" bpmnElement=\\"Task_Apply\\">\\n        <dc:Bounds x=\\"200\\" y=\\"80\\" width=\\"100\\" height=\\"80\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"Task_BranchApprove_di\\" bpmnElement=\\"Task_BranchApprove\\">\\n        <dc:Bounds x=\\"350\\" y=\\"80\\" width=\\"100\\" height=\\"80\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"Gateway_Approve_di\\" bpmnElement=\\"Gateway_Approve\\">\\n        <dc:Bounds x=\\"500\\" y=\\"95\\" width=\\"50\\" height=\\"50\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"Task_PowerApprove_di\\" bpmnElement=\\"Task_PowerApprove\\">\\n        <dc:Bounds x=\\"600\\" y=\\"80\\" width=\\"100\\" height=\\"80\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"Task_DispatchPlan_di\\" bpmnElement=\\"Task_DispatchPlan\\">\\n        <dc:Bounds x=\\"750\\" y=\\"80\\" width=\\"100\\" height=\\"80\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"Task_Operation_di\\" bpmnElement=\\"Task_Operation\\">\\n        <dc:Bounds x=\\"900\\" y=\\"80\\" width=\\"100\\" height=\\"80\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"ServiceTask_Notify_di\\" bpmnElement=\\"ServiceTask_Notify\\">\\n        <dc:Bounds x=\\"1050\\" y=\\"80\\" width=\\"100\\" height=\\"80\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"EndEvent_1_di\\" bpmnElement=\\"EndEvent_1\\">\\n        <dc:Bounds x=\\"1200\\" y=\\"100\\" width=\\"36\\" height=\\"36\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNShape id=\\"EndEvent_Reject_di\\" bpmnElement=\\"EndEvent_Reject\\">\\n        <dc:Bounds x=\\"500\\" y=\\"200\\" width=\\"36\\" height=\\"36\\" />\\n      </bpmndi:BPMNShape>\\n      <bpmndi:BPMNEdge id=\\"Flow_1_di\\" bpmnElement=\\"Flow_1\\">\\n        <di:waypoint x=\\"136\\" y=\\"118\\" />\\n <di:waypoint x=\\"200\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_2_di\\" bpmnElement=\\"Flow_2\\">\\n        <di:waypoint x=\\"300\\" y=\\"118\\" />\\n        <di:waypoint x=\\"350\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_3_di\\" bpmnElement=\\"Flow_3\\">\\n        <di:waypoint x=\\"450\\" y=\\"118\\" />\\n        <di:waypoint x=\\"500\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_4_di\\" bpmnElement=\\"Flow_4\\">\\n        <di:waypoint x=\\"550\\" y=\\"118\\" />\\n        <di:waypoint x=\\"600\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_5_di\\" bpmnElement=\\"Flow_5\\">\\n        <di:waypoint x=\\"525\\" y=\\"145\\" />\\n        <di:waypoint x=\\"525\\" y=\\"200\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_6_di\\" bpmnElement=\\"Flow_6\\">\\n        <di:waypoint x=\\"700\\" y=\\"118\\" />\\n        <di:waypoint x=\\"750\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_7_di\\" bpmnElement=\\"Flow_7\\">\\n        <di:waypoint x=\\"850\\" y=\\"118\\" />\\n        <di:waypoint x=\\"900\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_8_di\\" bpmnElement=\\"Flow_8\\">\\n        <di:waypoint x=\\"1000\\" y=\\"118\\" />\\n        <di:waypoint x=\\"1050\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n      <bpmndi:BPMNEdge id=\\"Flow_9_di\\" bpmnElement=\\"Flow_9\\">\\n        <di:waypoint x=\\"1150\\" y=\\"118\\" />\\n        <di:waypoint x=\\"1200\\" y=\\"118\\" />\\n      </bpmndi:BPMNEdge>\\n    </bpmndi:BPMNPlane>\\n  </bpmndi:BPMNDiagram>\\n</bpmn:definitions>"
