2. ScreenTitle06: x:480,y:20,w:960,h:90, title: "脉冲标题", option: { dataset: "用户活跃度监控大屏", subtitle: "实时监控", fontSize:46, accentColor: "#a78bfa", showBorder: true, showBackground: true, showDecorations: true }
