5. LineGradients: x:40,y:162,w:848,h:740, title: "双折线渐变面积图", option: { dataset: { dimensions: ["date", "新增用户", "登录次数"], source: [ {"date":"01-01","新增用户":12,"登录次数":120}, ... ] } }, request: { datasetId:1, datasetName: "test", datasetFields: ["create_time", "id", "login_count"], datasetMapping: { mode: "auto", fieldMap: { time: "create_time", series: ["新增用户", "登录次数"] }, outputFields: ["create_time", "id", "login_count"], syncHeader: true } }
