  <bpmn:process id="leavetest" name="请假流程" isExecutable="true">
    <bpmn:startEvent id="StartEvent_1" name="开始" flowable:initiator="initiator">
      <bpmn:outgoing>Flow_Start_Leader</bpmn:outgoing>
    </bpmn:startEvent>
    <bpmn:userTask id="Task_Leader" name="直属上级审批" flowable:assignee="${flowSpelService.getInitiatorLeader(execution)}">
      <bpmn:incoming>Flow_Start_Leader</bpmn:incoming>
      <bpmn:outgoing>Flow_Leader_Gateway</bpmn:outgoing>
    </bpmn:userTask>
    <bpmn:exclusiveGateway id="Gateway_1" name="天数判断">
      <bpmn:incoming>Flow_Leader_Gateway</bpmn:incoming>
      <bpmn:outgoing>Flow_Gateway_End</bpmn:outgoing>
      <bpmn:outgoing>Flow_Gateway_HR</bpmn:outgoing>
    </bpmn:exclusiveGateway>
    <bpmn:userTask id="Task_HR" name="HR 审批" flowable:candidateGroups="hr">
      <bpmn:incoming>Flow_Gateway_HR</bpmn:incoming>
      <bpmn:outgoing>Flow_HR_End</bpmn:outgoing>
    </bpmn:userTask>
    <bpmn:endEvent id="EndEvent_1" name="结束">
      <bpmn:incoming>Flow_Gateway_End</bpmn:incoming>
      <bpmn:incoming>Flow_HR_End</bpmn:incoming>
    </bpmn:endEvent>
    <bpmn:sequenceFlow id="Flow_Start_Leader" sourceRef="StartEvent_1" targetRef="Task_Leader" />
    <bpmn:sequenceFlow id="Flow_Leader_Gateway" sourceRef="Task_Leader" targetRef="Gateway_1" />
    <bpmn:sequenceFlow id="Flow_Gateway_End" sourceRef="Gateway_1" targetRef="EndEvent_1">
      <bpmn:conditionExpression xsi:type="bpmn:tFormalExpression">${days &lt;= 3}</bpmn:conditionExpression>
    </bpmn:sequenceFlow>
    <bpmn:sequenceFlow id="Flow_Gateway_HR" sourceRef="Gateway_1" targetRef="Task_HR">
      <bpmn:conditionExpression xsi:type="bpmn:tFormalExpression">${days &gt; 3}</bpmn:conditionExpression>
    </bpmn:sequenceFlow>
    <bpmn:sequenceFlow id="Flow_HR_End" sourceRef="Task_HR" targetRef="EndEvent_1" />
  </bpmn:process>
