  <bpmn:process id="leavetest" name="请假流程" isExecutable="true">
    <bpmn:startEvent id="StartEvent_1" name="开始" />
    <bpmn:userTask id="Task_Leader" name="直属上级审批" flowable:assignee="${flowSpelService.getInitiatorLeader(execution)}" flowable:assigneeType="spel" />
